#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

// Define the structure for a graph
typedef struct {
    int numVertices;
    int** adjLists;
} Graph;

// Function to create a graph
Graph* createGraph(int numVertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numVertices = numVertices;
    graph->adjLists = (int**) malloc(numVertices * sizeof(int*));
    for (int i = 0; i < numVertices; i++) {
        graph->adjLists[i] = NULL;
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    int* newNode = (int*) malloc(sizeof(int));
    *newNode = dest;
    newNode->next = graph->adjLists[src];
    graph->adjLists[src] = newNode;
}

// Function to detect a cycle using BFS
bool detectCycle(Graph* graph) {
    int* visited = (int*) malloc(graph->numVertices * sizeof(int));
    int* recursionStack = (int*) malloc(graph->numVertices * sizeof(int));
    for (int i = 0; i < graph->numVertices; i++) {
        visited[i] = 0;
        recursionStack[i] = 0;
    }
    for (int i = 0; i < graph->numVertices; i++) {
        if (visited[i] == 0) {
            if (isCyclicUtil(graph, i, visited, recursionStack)) {
                return true;
            }
        }
    }
    return false;
}

// Utility function to detect a cycle
bool isCyclicUtil(Graph* graph, int v, int* visited, int* recursionStack) {
    if (recursionStack[v] == 1) {
        return true;
    }
    if (visited[v] == 1) {
        return false;
    }
    visited[v] = 1;
    recursionStack[v] = 1;
    for (int i = 0; i < graph->numVertices; i++) {
        if (graph->adjLists[v][i] == 1) {
            if (isCyclicUtil(graph, i, visited, recursionStack)) {
                return true;
            }
        }
    }
    recursionStack[v] = 0;
    return false;
}

